import React, { useState } from "react";
import { useTranslation } from "react-i18next";
import { Button, theme } from "antd";
import { PlusOutlined, MinusOutlined, UndoOutlined } from "@ant-design/icons";
import Placement3DPage from "../simulation/3d";
import KonvaMap from "./KonvaMap";
import { useEffect } from "react";

// Sub-components
import DashboardHeader from "./DashboardHeader";
import SidebarOverlays from "./SidebarOverlays";
import EquipmentDetailOverlay from "./EquipmentDetailOverlay";
import DashboardModals from "./DashboardModals";
import { useSimulatedServer } from "../../hooks/useSimulatedServer";

const IntegratedDashboard: React.FC = () => {
  const { token } = theme.useToken();
  const { t } = useTranslation(["quarantine", "dashboard"]);

  const [mapMode, setMapMode] = useState("2D");
  const [isEventExpanded, setIsEventExpanded] = useState(false);
  const [detailEvent, setDetailEvent] = useState<any>(null);
  const [selectedEquipmentId, setSelectedEquipmentId] = useState<string | null>(null);

  // [VIRTUAL-SERVER-STREAM] 가상 서버로부터 실시간 텔레메트리 및 시나리오 데이터 수신
  const { devices: liveDevices, scenario: liveScenario } = useSimulatedServer();

  // 선택된 장비의 실시간 데이터 매핑
  const selectedEquipment = liveDevices.find(d => d.id === selectedEquipmentId) || null;

  const [isInfectionPopupOpen, setIsInfectionPopupOpen] = useState(false);
  const [isScenarioPopupOpen, setIsScenarioPopupOpen] = useState(false);
  const [isHistoryPopupOpen, setIsHistoryPopupOpen] = useState(false);
  const [equipmentDetailGroup, setEquipmentDetailGroup] = useState<string | null>(null);

  const [activeLeftTab, setActiveLeftTab] = useState<string | null>(null);
  const [activeRightTab, setActiveRightTab] = useState<string | null>(null);

  // 2D -> 3D 전환 시 팝업 닫기
  useEffect(() => {
    if (mapMode === "3D") {
      setSelectedEquipmentId(null);
    }
  }, [mapMode]);

  const getDonutOption = (label: string, current: number, total: number, alertColor: string) => ({
    series: [
      {
        type: "pie",
        radius: ["65%", "85%"],
        avoidLabelOverlap: false,
        label: { show: false },
        emphasis: { label: { show: false } },
        labelLine: { show: false },
        data: [
          {
            value: total - current, // 이상 발생 수 (Error + Warning)
            itemStyle: { color: alertColor }
          },
          {
            value: current, // 정상 상태 수
            itemStyle: { color: total === current ? token.colorSuccess : `${token.colorSuccess}40` }
          },
        ],
      },
    ],
  });

  return (
    <div className="w-full h-[calc(100vh-54px)] relative overflow-hidden flex flex-col" style={{ background: token.colorBgLayout, color: token.colorText }}>
      {/* 1. Header: Floating event bar */}
      <DashboardHeader
        isEventExpanded={isEventExpanded}
        setIsEventExpanded={setIsEventExpanded}
        mapMode={mapMode}
        setMapMode={setMapMode}
        setDetailEvent={setDetailEvent}
      />

      <div className="absolute inset-0 top-14 overflow-hidden" style={{ background: token.colorBgLayout }}>
        {/* 2D/3D Map Area */}
        <div
          className="absolute inset-0 z-0 transition-colors duration-500 overflow-hidden"
          style={{ background: token.colorBgLayout }}
        >
          {mapMode === "3D" ? (
            <Placement3DPage
              devices={liveDevices}
              selectedEquipment={selectedEquipment}
              onDeviceSelect={(d: any) => setSelectedEquipmentId(d?.id || null)}
            />
          ) : (
            <KonvaMap
              devices={liveDevices}
              selectedEquipment={selectedEquipment}
              onDeviceSelect={(d: any) => setSelectedEquipmentId(d?.id || null)}
            />
          )}
        </div>

        {/* Equipment Detail Popover Overlay */}
        <EquipmentDetailOverlay
          selectedEquipment={selectedEquipment}
          setSelectedEquipment={(d: any) => setSelectedEquipmentId(d?.id || null)}
        />

        {/* Sidebar UI Overlays */}
        <SidebarOverlays
          token={token}
          scenario={liveScenario}
          devices={liveDevices} // 실시간 장비 데이터 전달
          setEquipmentDetailGroup={setEquipmentDetailGroup} // 상세조회 트리거
          activeLeftTab={activeLeftTab}
          setActiveLeftTab={setActiveLeftTab}
          activeRightTab={activeRightTab}
          setActiveRightTab={setActiveRightTab}
          setIsInfectionPopupOpen={setIsInfectionPopupOpen}
          setIsScenarioPopupOpen={setIsScenarioPopupOpen}
          setIsHistoryPopupOpen={setIsHistoryPopupOpen}
          getDonutOption={getDonutOption}
        />

        {/* Global Map Controls (Zoom In/Out/Reset) */}
        <div className="absolute bottom-6 right-6 z-40 flex flex-col gap-2">
          <Button
            icon={<PlusOutlined />}
            className="w-10 h-10 backdrop-blur-md border-none shadow-xl flex items-center justify-center hover:scale-110 active:scale-95 transition-all"
            style={{ background: `${token.colorWhite}1A`, color: token.colorWhite }}
            onClick={() => {
              const suffix = mapMode === "3D" ? "3d" : "2d";
              window.dispatchEvent(new CustomEvent(`zoom-in-${suffix}`));
            }}
          />
          <Button
            icon={<MinusOutlined />}
            className="w-10 h-10 backdrop-blur-md border-none shadow-xl flex items-center justify-center hover:scale-110 active:scale-95 transition-all"
            style={{ background: `${token.colorWhite}1A`, color: token.colorWhite }}
            onClick={() => {
              const suffix = mapMode === "3D" ? "3d" : "2d";
              window.dispatchEvent(new CustomEvent(`zoom-out-${suffix}`));
            }}
          />
          <Button
            icon={<UndoOutlined />}
            className="w-10 h-10 backdrop-blur-md border-none shadow-xl flex items-center justify-center hover:scale-110 active:scale-95 transition-all"
            style={{ background: `${token.colorWhite}1A`, color: token.colorWhite }}
            onClick={() => {
              const suffix = mapMode === "3D" ? "3d" : "2d";
              window.dispatchEvent(new CustomEvent(`reset-${suffix}-camera`));
              setSelectedEquipmentId(null);
            }}
          />
        </div>
      </div>

      {/* Modals */}
      <DashboardModals
        scenario={liveScenario}
        devices={liveDevices}
        equipmentDetailGroup={equipmentDetailGroup}
        setEquipmentDetailGroup={setEquipmentDetailGroup}
        detailEvent={detailEvent}
        setDetailEvent={setDetailEvent}
        isInfectionPopupOpen={isInfectionPopupOpen}
        setIsInfectionPopupOpen={setIsInfectionPopupOpen}
        isScenarioPopupOpen={isScenarioPopupOpen}
        setIsScenarioPopupOpen={setIsScenarioPopupOpen}
        isHistoryPopupOpen={isHistoryPopupOpen}
        setIsHistoryPopupOpen={setIsHistoryPopupOpen}
      />

      <style>{`
        .animate-in { animation-duration: 0.3s; animation-timing-function: cubic-bezier(0.4, 0, 0.2, 1); }
        @keyframes slideInLeft { from { transform: translateX(-20px); opacity: 0; } to { transform: translateX(0); opacity: 1; } }
        .slide-in-from-left { animation-name: slideInLeft; }
        @keyframes slideInRight { from { transform: translateX(20px); opacity: 0; } to { transform: translateX(0); opacity: 1; } }
        .slide-in-from-right { animation-name: slideInRight; }
        @keyframes zoomIn { from { transform: scale(0.95); opacity: 0; } to { transform: scale(1); opacity: 1; } }
        .zoom-in-95 { animation-name: zoomIn; }
        @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }
        .fade-in { animation-name: fadeIn; }
      `}</style>
    </div>
  );
};

export default IntegratedDashboard;
