import React from "react";
import { useTranslation } from "react-i18next";
import { Row, Col, Typography, Button, Tag, theme } from "antd";
import { CloseOutlined, SettingOutlined, SearchOutlined } from "@ant-design/icons";
import { getStatusColor } from "../../constants";

const { Text } = Typography;

interface EquipmentDetailOverlayProps {
  selectedEquipment: any;
  setSelectedEquipment: (equipment: any) => void;
}

const EquipmentDetailOverlay: React.FC<EquipmentDetailOverlayProps> = ({
  selectedEquipment,
  setSelectedEquipment,
}) => {
  const { token } = theme.useToken();
  const { t } = useTranslation(["quarantine", "dashboard"]);

  if (!selectedEquipment) return null;

  return (
    <div className="absolute inset-0 z-50 flex items-center justify-end pr-10 pointer-events-none">
      <div className="pointer-events-auto flex gap-4 animate-in zoom-in-95 fade-in duration-300">
        {/* Left Side: Equipment Info & Metrics */}
        <div
          className="w-[340px] rounded-2xl p-6 shadow-2xl relative overflow-hidden backdrop-blur-xl border"
          style={{
            background: `${token.colorBgContainer}f2`,
            borderColor: token.colorBorderSecondary,
          }}
        >
          <Button
            type="text"
            icon={<CloseOutlined style={{ color: token.colorTextQuaternary, fontSize: 16 }} />}
            className="absolute top-5 left-5 w-8 h-8 flex items-center justify-center rounded-full hover:bg-white/10 transition-all border border-transparent hover:border-white/10"
            onClick={() => setSelectedEquipment(null)}
          />

          <div className="flex justify-between items-start mb-10 pt-4">
            <div>
              <Text className="font-bold block truncate" style={{ color: token.colorText, fontSize: 16, maxWidth: '180px' }} title={selectedEquipment.name}>
                {selectedEquipment.name}
              </Text>
              <Text style={{ color: token.colorTextQuaternary, fontSize: 13 }}>
                ({t(`dashboard:equipments.${selectedEquipment.type.toLowerCase()}`, { defaultValue: selectedEquipment.type })})
              </Text>
            </div>
            <div className="flex flex-col items-end gap-3">
              <Tag
                className="m-0 px-4 py-0.5 border-none font-bold"
                style={{
                  background: `${getStatusColor(selectedEquipment.status)}26`,
                  color: getStatusColor(selectedEquipment.status),
                  border: `1px solid ${getStatusColor(selectedEquipment.status)}40`,
                  borderRadius: 6,
                  fontSize: 13
                }}
              >
                {t(`dashboard:status.${selectedEquipment.status.toLowerCase()}`, { defaultValue: selectedEquipment.status })}
              </Tag>
              <Button
                type="primary"
                className="w-12 h-12 flex items-center justify-center p-0 rounded-2xl shadow-lg hover:scale-105 transition-all"
                icon={<SettingOutlined style={{ fontSize: 22 }} />}
                title={t("dashboard:equipment.remoteControl")}
                style={{ 
                  background: `linear-gradient(135deg, ${token.colorPrimary} 0%, ${token.colorInfo} 100%)`,
                  border: 'none',
                  boxShadow: `0 4px 15px ${token.colorPrimary}40`
                }}
              />
            </div>
          </div>

          <Row gutter={20}>
            <Col span={10}>
              <Text
                className="font-black block mb-3 uppercase"
                style={{ color: token.colorTextQuaternary, fontSize: 11, letterSpacing: '0.05em' }}
              >
                {t("dashboard:equipment.controlItems")}
              </Text>
              <div
                className="w-full h-32 rounded-2xl border border-dashed flex items-center justify-center p-4 overflow-hidden"
                style={{ background: 'rgba(0,0,0,0.2)', borderColor: token.colorBorderSecondary }}
              >
                  {(selectedEquipment.icon || selectedEquipment.deviceGrpCd) && (
                    <img 
                      src={selectedEquipment.icon || `${import.meta.env.BASE_URL}assets/platforms/quarantine/equipment/${selectedEquipment.deviceGrpCd}`} 
                      alt="control" 
                      className="w-full h-full object-contain filter drop-shadow-lg" 
                    />
                  )}
              </div>
            </Col>
            <Col span={14}>
              <Text
                className="font-black block mb-3 uppercase"
                style={{ color: token.colorTextQuaternary, fontSize: 11, letterSpacing: '0.05em' }}
              >
                {t("dashboard:equipment.collectionItems")}
              </Text>
              <div className="flex flex-col gap-2">
                {[
                  { label: "humidity", val: selectedEquipment.metrics?.hum || "45%", color: "processing" },
                  { label: "battery", val: selectedEquipment.metrics?.batt || "80%", color: "success" },
                  { label: "temperature", val: selectedEquipment.metrics?.temp || "22.5°C", color: "warning" },
                ].map((m) => (
                  <div
                    key={m.label}
                    className="flex items-center justify-between px-3 py-1.5 rounded-xl border border-white/5"
                    style={{ background: 'rgba(0,0,0,0.15)' }}
                  >
                    <Text style={{ color: token.colorTextSecondary, fontSize: 12 }}>{t(`dashboard:equipment.${m.label}`)}</Text>
                    <Text className="font-mono font-bold" style={{ color: token.colorText, fontSize: 13 }}>
                      {m.val}
                    </Text>
                  </div>
                ))}
            </div>
          </Col>
          </Row>

          {/* Bottom Coordinates Section */}
          <div className="mt-8 pt-6 border-t" style={{ borderColor: token.colorBorderSecondary }}>
             <Text
              className="font-black block mb-4 uppercase"
              style={{ color: token.colorTextQuaternary, fontSize: 11, letterSpacing: '1px' }}
            >
              {t("dashboard:equipment.coordinates")}
            </Text>
            <div className="grid grid-cols-3 gap-3">
              {['xAxis', 'yAxis', 'zAxis'].map((key) => {
                const axis = key[0].toUpperCase();
                return (
                  <div 
                    key={key}
                    className="px-3 py-3 rounded-2xl flex flex-col items-center border shadow-inner"
                    style={{ background: 'rgba(0,0,0,0.25)', borderColor: token.colorBorderSecondary }}
                  >
                    <Text style={{ color: token.colorTextQuaternary, fontSize: 10, fontWeight: '900' }}>{t(`dashboard:equipment.${key}`)}</Text>
                    <Text className="font-mono font-bold" style={{ color: token.colorText, fontSize: 15, marginTop: 4 }}>
                      {selectedEquipment[axis.toLowerCase()]?.toFixed(1) || '0.0'}
                    </Text>
                  </div>
                );
              })}
            </div>
          </div>
        </div>

        {/* Right Side: Matching Items (Camera Feed Mockup) */}
        {selectedEquipment.matching && (
          <div
            className="w-[340px] rounded-2xl p-6 shadow-2xl backdrop-blur-xl border flex flex-col animate-in slide-in-from-right duration-500"
            style={{
              background: `${token.colorBgContainer}f2`,
              borderColor: token.colorBorderSecondary,
            }}
          >
            <Text
              className="uppercase font-black block mb-6"
              style={{ color: token.colorTextQuaternary, fontSize: 13 }}
            >
              {t("dashboard:equipment.matchingItems")}
            </Text>
            <div className="mb-4">
              <Text className="font-bold block" style={{ color: token.colorText, fontSize: 14 }}>
                {selectedEquipment.matching?.name || t("dashboard:equipments.thermalCamera")}
              </Text>
              <Text style={{ color: token.colorTextQuaternary, fontSize: 13 }}>
                ({selectedEquipment.matching?.type || t("dashboard:equipments.thermalCamera")})
              </Text>
            </div>
            
            {selectedEquipment.type !== "Tunnel" && !selectedEquipment.id?.startsWith("T-") && (
              <div
                className="aspect-square rounded-3xl border flex flex-col items-center justify-center p-8 mt-8"
                style={{ background: token.colorBgLayout, borderColor: token.colorBorderSecondary }}
              >
                <div
                  className="w-full h-full rounded-2xl border flex items-center justify-center relative overflow-hidden group p-8"
                  style={{ background: token.colorBgBase, borderColor: token.colorBorderSecondary }}
                >
                  <img 
                    src={selectedEquipment.matching?.icon || `${import.meta.env.BASE_URL}assets/platforms/quarantine/equipment/feverCam.svg`} 
                    alt="Matching Item"
                    className="w-full h-full object-contain"
                  />
                  <div 
                    className="absolute inset-0 border-2 border-dashed border-primary/30 rounded-2xl animate-pulse"
                    style={{ borderColor: `${token.colorPrimary}40` }}
                  />
                </div>
                <Text
                  className="font-bold tracking-widest uppercase mt-4"
                  style={{ color: token.colorPrimary, fontSize: 12 }}
                >
                  LIVE STREAMING
                </Text>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

export default EquipmentDetailOverlay;
