import { useState, useEffect, useRef } from 'react';
import { QUARANTINE_DB } from '../mocks/db';

/**
 * [VIRTUAL-SERVER-SIMULATOR] 
 * 실제 백엔드 없이도 장비의 실시간 이동 및 센서 데이터를 시뮬레이션합니다.
 */
export const useSimulatedServer = () => {
  const [devices, setDevices] = useState(QUARANTINE_DB.devices);
  const [scenario, setScenario] = useState(QUARANTINE_DB.scenarios); // [SCENARIO-LIVE-STATE]
  const targetsRef = useRef<{ [key: string]: { x: number; y: number } }>({});

  useEffect(() => {
    const interval = setInterval(() => {
      const activeScenario = scenario;
      const scenarioTargetId = activeScenario.activeLandmarkId;
      const assignedDevices = activeScenario.assignedDevices || [];

      let totalProgressGain = 0;

      const nextDevices = devices.map(device => {
        if (device.type !== 'Robot') return device;

        // 시나리오 타겟 설정
        let target = targetsRef.current[device.id];
        const isAssigned = assignedDevices.includes(device.id);

        if (isAssigned && scenarioTargetId) {
          const landmark = QUARANTINE_DB.landmarks.find(l => l.id === scenarioTargetId);
          if (landmark) target = { x: landmark.x, y: landmark.y };
        }

        if (!target) {
          const randomLandmark = QUARANTINE_DB.landmarks[Math.floor(Math.random() * QUARANTINE_DB.landmarks.length)];
          target = { x: randomLandmark.x, y: randomLandmark.y };
        }
        
        targetsRef.current[device.id] = target;

        const dx = target.x - device.x;
        const dy = target.y - device.y;
        const distance = Math.sqrt(dx * dx + dy * dy);

        // 도착 및 진행률 기여
        if (distance < 15) {
          if (isAssigned) {
            totalProgressGain += 0.1; // 작전 투입 로봇이 거점에 있으면 진행률 상승
            return {
              ...device,
              x: device.x + (Math.random() - 0.5) * 5,
              y: device.y + (Math.random() - 0.5) * 5
            };
          }
          delete targetsRef.current[device.id];
          return device;
        }

        const speed = isAssigned ? 8 : 4; // [REALISTIC-SPEED] 안전을 고려한 서행 (8px/s, 4px/s)
        const vx = (dx / distance) * speed;
        const vy = (dy / distance) * speed;

        return {
          ...device,
          x: device.x + vx,
          y: device.y + vy,
          metrics: {
            ...device.metrics,
            batt: (parseFloat(device.metrics.batt) - 0.01).toFixed(2) + "%" // 배터리 소모량도 더 세밀하게
          }
        };
      });

      setDevices(nextDevices);

      // 시나리오 진행률 및 상태 텍스트 실시간 갱신
      setScenario(prev => {
        const newProgress = Math.min(99.9, prev.progress + totalProgressGain);
        const isRobotArrived = totalProgressGain > 0;
        
        return {
          ...prev,
          progress: parseFloat(newProgress.toFixed(1)),
          // [DYNAMIC-STATUS] 로봇의 위치에 따른 시나리오 단계 텍스트 변경
          activeStatusMsg: isRobotArrived ? "Performing Quarantine Screening..." : "Dispatching Agents to Gateway A1...",
        };
      });

    }, 1000);

    return () => clearInterval(interval);
  }, [devices, scenario]);

  return { devices, scenario };
};
