import React from "react";
import { useTranslation } from "react-i18next";
import {
  Modal,
  Typography,
  Space,
  Button,
  Row,
  Col,
  Progress,
  Tag,
  Flex,
} from "antd";
import { CloseOutlined } from "@ant-design/icons";
import ReactECharts from "echarts-for-react";
import * as echarts from "echarts";
import worldJson from "../../assets/map/world.json";
import { QUARANTINE_DB } from "../../mocks/db";
import { getStatusColor } from "../../constants";

echarts.registerMap("world", worldJson as any);

const { Text } = Typography;
const MAP_DATA = [
  { name: "United States", id: "usa", value: 94536664 },
  { name: "India", id: "india", value: 44553042 },
  { name: "France", id: "france", value: 38413875 },
  { name: "Germany", id: "germany", value: 37504502 },
  { name: "Brazil", id: "brazil", value: 34700000 },
  { name: "Korea", id: "korea", value: 31800000 },
];

interface DashboardModalsProps {
  scenario?: any;
  devices?: any[];
  equipmentDetailGroup: string | null;
  setEquipmentDetailGroup: (group: string | null) => void;
  detailEvent: any;
  setDetailEvent: (event: any) => void;
  isInfectionPopupOpen: boolean;
  setIsInfectionPopupOpen: (open: boolean) => void;
  isScenarioPopupOpen: boolean;
  setIsScenarioPopupOpen: (open: boolean) => void;
  isHistoryPopupOpen: boolean;
  setIsHistoryPopupOpen: (open: boolean) => void;
}

const DashboardModals: React.FC<DashboardModalsProps> = ({
  scenario,
  devices,
  equipmentDetailGroup,
  setEquipmentDetailGroup,
  detailEvent,
  setDetailEvent,
  isInfectionPopupOpen,
  setIsInfectionPopupOpen,
  isScenarioPopupOpen,
  setIsScenarioPopupOpen,
  isHistoryPopupOpen,
  setIsHistoryPopupOpen,
}) => {
  const { t } = useTranslation(["quarantine", "dashboard"]);
  
  const currentScenario = scenario || QUARANTINE_DB.scenarios;
  const liveDevices = devices || QUARANTINE_DB.devices;

  const assignedRobotList = liveDevices.filter(d => currentScenario.assignedDevices?.includes(d.id));
  const primaryAgent = QUARANTINE_DB.agents[0];

  const filteredDevices = liveDevices.filter(d => {
    if (!equipmentDetailGroup) return false;
    if (equipmentDetailGroup === "all") return true; 
    
    const grpMap: Record<string, string> = {
      baggageDisinfector: "baggage.svg",
      quarantineRobot: "disinfectionRobot.svg",
      thermalCamera: "feverCam.svg",
      serviceRobot: "serviceRobot.svg"
    };
    return d.deviceGrpCd === grpMap[equipmentDetailGroup];
  });

  const [activeCountry, setActiveCountry] = React.useState<string | null>(null);
  const echartsRef = React.useRef<any>(null);

  React.useEffect(() => {
    if (echartsRef.current) {
      const chart = echartsRef.current.getEchartsInstance();
      if (activeCountry) {
        chart.dispatchAction({ type: "downplay", seriesIndex: 0 });
        chart.dispatchAction({ type: "highlight", seriesIndex: 0, name: activeCountry });
        chart.dispatchAction({ type: "showTip", seriesIndex: 0, name: activeCountry });
      } else {
        chart.dispatchAction({ type: "downplay", seriesIndex: 0 });
        chart.dispatchAction({ type: "hideTip" });
      }
    }
  }, [activeCountry]);

  const onEvents = {
    mouseover: (params: any) => {
      if (params.seriesType === "map") setActiveCountry(params.name);
    },
    mouseout: () => setActiveCountry(null),
  };

  // 모든 배경을 투명하게 설정하여 메인 배경(#1a1a1a)만 남김
  const transparentModalStyles = {
    mask: { backdropFilter: "blur(4px)" },
    content: { background: "#1a1a1a", padding: 0 },
    header: { background: "transparent", padding: "32px 40px 10px", border: "none" },
    body: { background: "transparent", padding: "0 40px 32px" },
    footer: { background: "transparent", padding: "0 40px 40px", border: "none" },
  };

  const closeIconStyle = { color: "rgba(255,255,255,0.45)", fontSize: 18 };
  const btnNoStyle = { background: "#2b2b2b", color: "#ffffff", border: "none", height: 44, padding: "0 32px", fontWeight: "bold", borderRadius: 4 };
  const btnYesStyle = { background: "#5d87d9", color: "#ffffff", border: "none", height: 44, padding: "0 32px", fontWeight: "bold", borderRadius: 4 };

  return (
    <>
      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 6px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.1); border-radius: 10px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: rgba(255,255,255,0.2); }
        .flat-label { color: rgba(255,255,255,0.45); font-size: 13px; font-weight: bold; margin-bottom: 8px; display: block; }
        .flat-value { color: #ffffff; font-size: 15px; font-weight: normal; }
      `}</style>

      {/* 1. Event Detail Modal */}
      <Modal
        title={<Text style={{ color: "#ffffff", fontSize: 18, fontWeight: "bold" }}>{t("dashboard:eventDetail")}</Text>}
        open={!!detailEvent}
        onCancel={() => setDetailEvent(null)}
        footer={[
          <div key="footer" className="flex justify-end pt-0">
            <Button onClick={() => setDetailEvent(null)} style={btnYesStyle}>{t("quarantine:common.confirm")}</Button>
          </div>
        ]}
        centered
        width={480}
        styles={transparentModalStyles}
        closeIcon={<CloseOutlined style={closeIconStyle} />}
      >
        <div className="space-y-8 py-6">
           <div>
              <span className="flat-label">{t("dashboard:event.time")}</span>
              <div className="flat-value font-mono">{detailEvent?.time}</div>
           </div>
           <div>
              <span className="flat-label">{t("dashboard:event.content")}</span>
              <div className="flat-value text-lg font-bold">{detailEvent?.content && t(`dashboard:${detailEvent.content}`)}</div>
           </div>
        </div>
      </Modal>

      {/* 2. Infection Status Modal */}
      <Modal
        title={<Text style={{ color: "#ffffff", fontSize: 20, fontWeight: "bold" }}>{t("dashboard:infectionStatus")}</Text>}
        open={isInfectionPopupOpen}
        onCancel={() => setIsInfectionPopupOpen(false)}
        footer={[
          <div key="footer" className="flex justify-end pt-0">
            <Button onClick={() => setIsInfectionPopupOpen(false)} style={btnNoStyle}>{t("quarantine:common.close")}</Button>
          </div>
        ]}
        width={1320}
        centered
        styles={transparentModalStyles}
        closeIcon={<CloseOutlined style={closeIconStyle} />}
      >
        <div className="space-y-10">
          <div className="flex justify-between items-baseline border-b border-white/5 pb-6">
             <div className="flex items-center gap-10">
               <span className="flat-label mb-0">{t("dashboard:responseLevel")}</span>
               <div className="flex gap-2">
                 {[1, 2, 3, 4, 5].map((lv) => (
                   <div key={lv} className="w-10 h-10 rounded-sm flex items-center justify-center font-black" 
                     style={{ background: lv === 2 ? "#facd14" : "rgba(255,255,255,0.05)", color: lv === 2 ? "#000" : "rgba(255,255,255,0.2)" }}>
                     {lv}
                   </div>
                 ))}
               </div>
             </div>
             <Text className="font-mono" style={{ color: "rgba(255,255,255,0.2)", fontSize: 13 }}>23-07-07 13:21:06</Text>
          </div>
          <Row gutter={40}>
            <Col span={15}>
              <div className="h-[600px]"><ReactECharts option={{ backgroundColor: "transparent", series: [{ type: "map", map: "world", data: MAP_DATA, itemStyle: { areaColor: "#222", borderColor: "#333" } }] }} onEvents={onEvents} ref={echartsRef} style={{ height: "100%" }} /></div>
            </Col>
            <Col span={9} className="flex flex-col h-[600px]">
              <span className="flat-label uppercase tracking-widest">{t("dashboard:stats.globalRanking")}</span>
              <div className="flex-1 overflow-auto custom-scrollbar">
                {MAP_DATA.map(item => (
                  <div key={item.id} className="py-5 border-b border-white/5 flex justify-between items-center pr-4">
                    <span className="flat-value">{t(`dashboard:regions.${item.id}`)}</span>
                    <span className="flat-value font-black" style={{ color: "#5d87d9" }}>{item.value.toLocaleString()}</span>
                  </div>
                ))}
              </div>
            </Col>
          </Row>
        </div>
      </Modal>

      {/* 3. Scenario Progress Modal */}
      <Modal
        title={<Text style={{ color: "#ffffff", fontSize: 20, fontWeight: "bold" }}>{t("dashboard:scenario.progressStatus")}</Text>}
        open={isScenarioPopupOpen}
        onCancel={() => setIsScenarioPopupOpen(false)}
        footer={[
          <div key="footer" className="flex justify-end pt-0">
             <Button onClick={() => setIsScenarioPopupOpen(false)} style={btnYesStyle}>{t("quarantine:common.confirm")}</Button>
          </div>
        ]}
        width={1000}
        centered
        styles={transparentModalStyles}
        closeIcon={<CloseOutlined style={closeIconStyle} />}
      >
        <div className="space-y-12 max-h-[calc(100vh-350px)] overflow-auto custom-scrollbar pr-2">
          <div>
            <div className="flex justify-between items-end mb-4">
              <span className="flat-value text-2xl font-black">{t(`dashboard:${currentScenario.activeTitle}`)}</span>
              <Tag color="processing" style={{ background: "rgba(93,135,217,0.1)", color: "#5d87d9", border: "1px solid rgba(93,135,217,0.2)", borderRadius: 2 }}>{t("dashboard:progress")} ({t("dashboard:levelFormat", { val: 2 })})</Tag>
            </div>
            <div className="mb-8 flat-value" style={{ color: "#5d87d9" }}>{currentScenario.activeStatusMsg}</div>
            <Progress percent={currentScenario.progress} strokeColor="#5d87d9" trailColor="rgba(255,255,255,0.05)" strokeWidth={12} strokeLinecap="square" />
          </div>

          <Row gutter={60}>
            <Col span={14}>
              <span className="flat-label uppercase tracking-widest mb-6">{t("dashboard:scenario.assignedEquipment")}</span>
              <div className="space-y-6">
                {assignedRobotList.map(r => (
                  <div key={r.id} className="flex items-center gap-6 group">
                    <div className="w-14 h-14 bg-white/5 rounded-sm p-2 flex items-center justify-center grayscale group-hover:grayscale-0 transition-all border border-white/5">
                      <img src={`${import.meta.env.BASE_URL}assets/platforms/quarantine/equipment/${r.deviceGrpCd}`} className="w-full h-full object-contain" />
                    </div>
                    <div className="flex-1">
                      <div className="flat-value font-bold">{r.name}</div>
                      <div style={{ fontSize: 12, color: "rgba(255,255,255,0.2)" }}>{r.details.itemGrpNm}</div>
                    </div>
                    <Tag style={{ background: "transparent", color: getStatusColor(r.status), border: `1px solid ${getStatusColor(r.status)}40`, borderRadius: 2, fontSize: 10 }}>{r.status.toUpperCase()}</Tag>
                  </div>
                ))}
              </div>
            </Col>
            <Col span={10}>
              <span className="flat-label uppercase tracking-widest mb-6">{t("dashboard:scenario.responsibleAgent")}</span>
              <div className="flex items-center gap-6">
                <div className="w-16 h-16 rounded-full bg-white/5 border border-white/10 flex items-center justify-center text-2xl grayscale">👤</div>
                <div>
                  <div className="flat-value font-black text-lg">{primaryAgent.name}</div>
                  <div className="flat-value mt-1" style={{ color: "rgba(255,255,255,0.3)", fontSize: 13 }}>{t(`dashboard:scenario.roles.${primaryAgent.role}`, { defaultValue: primaryAgent.role })}</div>
                </div>
              </div>
            </Col>
          </Row>

          <div>
             <span className="flat-label uppercase tracking-widest mb-6">{t("dashboard:scenario.actionStatus")}</span>
             <div className="space-y-4">
                {currentScenario.actions?.map((action: any) => (
                  <div key={action.id} className="flex items-center gap-6 py-4 border-b border-white/5 font-medium">
                    <span className="font-mono font-black" style={{ color: "rgba(255,255,255,0.15)", width: 24 }}>{action.id}</span>
                    <span className="flex-1 flat-value">{action.content}</span>
                    <div className="w-10 h-5 border border-white/10 rounded-sm relative flex items-center px-0.5" style={{ background: action.confirmed ? "#5d87d9" : "transparent" }}>
                      <div className="w-3.5 h-3.5 bg-white shadow-sm transition-all" style={{ transform: action.confirmed ? "translateX(20px)" : "translateX(0px)" }} />
                    </div>
                  </div>
                ))}
             </div>
          </div>
        </div>
      </Modal>

      {/* 4. Equipment History Modal */}
      <Modal
        title={<Text style={{ color: "#ffffff", fontSize: 20, fontWeight: "bold" }}>{t("dashboard:history")}</Text>}
        open={isHistoryPopupOpen}
        onCancel={() => setIsHistoryPopupOpen(false)}
        footer={[
          <div key="footer" className="flex justify-end pt-0">
             <Button onClick={() => setIsHistoryPopupOpen(false)} style={btnYesStyle}>{t("quarantine:common.confirm")}</Button>
          </div>
        ]}
        width={1100}
        centered
        styles={transparentModalStyles}
        closeIcon={<CloseOutlined style={closeIconStyle} />}
      >
        <div className="px-10 pb-10 max-h-[600px] overflow-auto custom-scrollbar">
          <table className="w-full">
            <thead>
              <tr className="text-left border-b border-white/10">
                <th className="pb-4 flat-label mb-0">{t("quarantine:common.status").toUpperCase()}</th>
                <th className="pb-4 flat-label mb-0">{t("quarantine:common.group").toUpperCase()}</th>
                <th className="pb-4 flat-label mb-0">{t("quarantine:common.name").toUpperCase()}</th>
                <th className="pb-4 flat-label mb-0">{t("quarantine:common.time").toUpperCase()}</th>
              </tr>
            </thead>
            <tbody>
              {QUARANTINE_DB.history.map((h, i) => (
                <tr key={i} className="border-b border-white/5 hover:bg-white/5 transition-colors">
                  <td className="py-5 font-bold" style={{ color: h.status === 'success' ? '#52c41a' : '#f5222d' }}>{h.status.toUpperCase()}</td>
                  <td className="py-5 flat-value">{h.target}</td>
                  <td className="py-5 flat-value font-bold">{t(`dashboard:${h.action}`)}</td>
                  <td className="py-5 font-mono" style={{ color: "rgba(255,255,255,0.2)", fontSize: 13 }}>{h.time}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </Modal>

      {/* 5. Equipment Detail Modal */}
      <Modal
        title={<Text style={{ color: "#ffffff", fontSize: 20, fontWeight: "bold" }}>
          {equipmentDetailGroup === "all" ? t("dashboard:allEquipment") : t(`dashboard:equipments.${equipmentDetailGroup}`)} {t("dashboard:equipment.status")}
        </Text>}
        open={!!equipmentDetailGroup}
        onCancel={() => setEquipmentDetailGroup(null)}
        footer={[
          <div key="footer" className="flex justify-end pt-0">
            <Button onClick={() => setEquipmentDetailGroup(null)} style={btnNoStyle}>{t("quarantine:common.confirm")}</Button>
          </div>
        ]}
        width={1100}
        centered
        styles={transparentModalStyles}
        closeIcon={<CloseOutlined style={closeIconStyle} />}
      >
        <div className="max-h-[600px] overflow-auto custom-scrollbar">
           {filteredDevices.map(d => (
             <div key={d.id} className="py-6 border-b border-white/5 flex items-center group hover:bg-white/[0.02] transition-colors px-4">
               {/* 1. Identity Area: Icon + Name/ID (Flexible) */}
               <div className="flex items-center gap-8 flex-1 min-w-0">
                  <div className="w-16 h-16 bg-white/5 border border-white/10 p-2 grayscale group-hover:grayscale-0 transition-all transition-duration-500">
                    <img src={`${import.meta.env.BASE_URL}assets/platforms/quarantine/equipment/${d.deviceGrpCd}`} className="w-full h-full object-contain" />
                  </div>
                  <div className="min-w-0">
                    <div className="flat-value font-black text-lg truncate">{d.name}</div>
                    <div style={{ fontSize: 11, color: "rgba(255,255,255,0.2)", fontFamily: "monospace", marginTop: 4 }}>{d.id}</div>
                  </div>
               </div>

               {/* 2. Status Area: Centered Alignment (Fixed Width) */}
               <div className="w-64 flex justify-center">
                  <Tag style={{ 
                    background: "transparent", 
                    color: getStatusColor(d.status), 
                    border: `1px solid ${getStatusColor(d.status)}40`, 
                    borderRadius: 2,
                    minWidth: 80,
                    textAlign: "center",
                    fontWeight: "bold",
                    fontSize: 11
                  }}>
                    {t(`quarantine:common.${d.status.toLowerCase()}`).toUpperCase()}
                  </Tag>
               </div>

               {/* 3. Metrics Area (Right Aligned) */}
               <div className="w-48 text-right flex flex-col justify-center">
                  <span className="flat-label mb-1" style={{ fontSize: 10, opacity: 0.5 }}>{t("dashboard:equipment.battery").toUpperCase()}</span>
                  <span className="flat-value font-mono text-xl tracking-tighter" style={{ color: d.metrics.batt === "AC Power" ? "#5d87d9" : "inherit" }}>
                    {d.metrics.batt}
                  </span>
               </div>
             </div>
           ))}
        </div>
      </Modal>
    </>
  );
};

export default DashboardModals;
