import React, { useState, useRef, useEffect } from 'react';
import { Stage, Layer, Rect, Text, Group, Line } from 'react-konva';
import { Button, theme } from 'antd';
import { PlusOutlined, MinusOutlined, UndoOutlined } from '@ant-design/icons';
import { useTranslation } from 'react-i18next';
import Konva from 'konva';
import { getStatusColor } from '../../constants';
import { Image as KonvaImage } from 'react-konva';

const ASSET_PATH = `${import.meta.env.BASE_URL}assets/platforms/quarantine/equipment`;

const DeviceIcon = ({ url, x, y, size = 42, opacity = 1 }: { url: string, x: number, y: number, size?: number, opacity?: number }) => {
  const [image, setImage] = useState<HTMLImageElement | null>(null);

  React.useEffect(() => {
    const img = new window.Image();
    img.src = url;
    img.onload = () => {
      setImage(img);
    };
  }, [url]);

  if (!image) return null;

  return (
    <KonvaImage
      image={image}
      x={x}
      y={y}
      width={size}
      height={size}
      offset={{ x: size / 2, y: size / 2 }}
      opacity={opacity}
    />
  );
};

const StatusIndicator = ({ x, y, color, status, token }: { x: number, y: number, color: string, status: string, token: any }) => {
  const [opacity, setOpacity] = React.useState(1);
  const isWarning = status === 'warning' || status === 'error' || status === 'Error' || status === 'Warning';

  React.useEffect(() => {
    if (!isWarning) {
      setOpacity(1);
      return;
    }
    const interval = setInterval(() => {
      setOpacity(prev => (prev === 1 ? 0.3 : 1));
    }, 600);
    return () => clearInterval(interval);
  }, [isWarning]);

  return (
    <Rect
      x={x} y={y} width={12} height={12}
      fill={color}
      cornerRadius={6}
      shadowBlur={isWarning ? 18 : 10}
      shadowColor={color}
      opacity={opacity}
    />
  );
};

interface KonvaMapProps {
  devices: any[];
  selectedEquipment: any;
  onDeviceSelect: (device: any) => void;
}

import { QUARANTINE_DB } from "../../mocks/db";

const MapBackground = ({ url, width, height }: { url: string, width: number, height: number }) => {
  const [canvas, setCanvas] = useState<HTMLCanvasElement | null>(null);

  useEffect(() => {
    const img = new window.Image();
    img.src = url;
    img.onload = () => {
      // [PRE-RENDERING] SVG를 고해상도 캔버스에 미리 그려서 비트맵화
      const offCanvas = document.createElement('canvas');
      const scale = 2; // 고해상도 유지를 위해 2배 스케일로 렌더링
      offCanvas.width = width * scale;
      offCanvas.height = height * scale;

      const ctx = offCanvas.getContext('2d');
      if (ctx) {
        ctx.imageSmoothingEnabled = true;
        ctx.imageSmoothingQuality = 'high';
        ctx.drawImage(img, 0, 0, width * scale, height * scale);
        setCanvas(offCanvas); // 이제부터는 수천개의 선이 아닌, '이미지'로 취급됨
      }
    };
  }, [url, width, height]);

  if (!canvas) return null;

  return (
    <KonvaImage
      image={canvas}
      x={0}
      y={0}
      width={width}
      height={height}
      opacity={0.8}
      listening={false}
      perfectDrawEnabled={false}
    />
  );
};

const KonvaMap: React.FC<KonvaMapProps> = ({ devices, selectedEquipment, onDeviceSelect }) => {
  const { token } = theme.useToken();
  const { t } = useTranslation(["quarantine", "dashboard"]);
  const stageRef = useRef<Konva.Stage>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const [dimensions, setDimensions] = useState({ width: 1000, height: 600 });
  const [scale, setScale] = useState(1);
  const [position, setPosition] = useState({ x: 500, y: 300 });
  const [rotation, setRotation] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const movingTimeout = useRef<any>(null);
  const rotationStartRef = useRef<{ angle: number; startRotation: number } | null>(null);

  // 이동 시작/종료 감지 함수
  const startMoving = () => {
    setIsMoving(true);
    if (movingTimeout.current) clearTimeout(movingTimeout.current);
  };

  const stopMoving = () => {
    movingTimeout.current = setTimeout(() => {
      setIsMoving(false);
    }, 150);
  };

  // [CALIBRATION-SYNC] DB의 캘리브레이션 설정을 2D 엔진에 실시간 적용
  const { offsetX, offsetY, invX, invY } = QUARANTINE_DB.mapCalibration;

  const equipmentItems = devices.map(d => {
    const displayX = ((d.x - offsetX) * (invX ? -1 : 1)) + offsetX;
    const displayY = ((d.y - offsetY) * (invY ? -1 : 1)) + offsetY;
    return {
      ...d,
      x: displayX,
      y: displayY,
      icon: `${ASSET_PATH}/${d.deviceGrpCd}`,
      displayType: d.deviceGrpCd
    };
  });

  useEffect(() => {
    if (!containerRef.current) return;

    const updateSize = () => {
      if (containerRef.current) {
        const { clientWidth, clientHeight } = containerRef.current;
        setDimensions({ width: clientWidth, height: clientHeight });
        // Only set initial position if it was at default
        setPosition(prev => prev.x === 500 && prev.y === 300 ? { x: clientWidth / 2, y: clientHeight / 2 } : prev);
      }
    };

    const observer = new ResizeObserver(updateSize);
    observer.observe(containerRef.current);
    updateSize();

    // [PASSIVE-EVENT-FIX] Stage 컨테이너 레벨에서 패시브 정책 강제 해제
    const stage = stageRef.current;
    if (stage) {
      const container = stage.container();
      container.addEventListener('wheel', (e) => {
        // 브라우저 경고 박멸을 위해 패시브가 아님을 강제 명시하며 이벤트 전달
      }, { passive: false });
    }

    return () => {
      observer.disconnect();
    };
  }, []);

  const handleWheel = (e: any) => {
    e.evt.preventDefault();
    startMoving(); // 이동 시작 알림

    const stage = stageRef.current;
    if (!stage) return;

    const oldScale = stage.scaleX();
    const pointer = stage.getPointerPosition();
    if (!pointer) return;

    const mousePointTo = {
      x: (pointer.x - stage.x()) / oldScale,
      y: (pointer.y - stage.y()) / oldScale,
    };

    const speed = 1.1;
    const newScale = e.evt.deltaY > 0 ? oldScale / speed : oldScale * speed;

    // Scale limit
    if (newScale < 0.2 || newScale > 5) return;

    setScale(newScale);
    setPosition({
      x: pointer.x - mousePointTo.x * newScale,
      y: pointer.y - mousePointTo.y * newScale,
    });

    stopMoving(); // 이동 종료 체크 예약
  };

  const handleMouseDown = (e: any) => {
    // [ROTATE-LOGIC] 오른쪽 마우스(2) 클릭 시 회전 시작
    if (e.evt.button === 2) {
      const stage = stageRef.current;
      if (!stage) return;
      const pointer = stage.getPointerPosition();
      if (!pointer) return;

      const centerX = position.x;
      const centerY = position.y;
      
      const angle = Math.atan2(pointer.y - centerY, pointer.x - centerX) * 180 / Math.PI;
      rotationStartRef.current = { angle, startRotation: rotation };
      startMoving();
    }
  };

  const handleMouseMove = (e: any) => {
    // 오른쪽 마우스 버튼이 눌려 있는 상태에서만 회전 처리
    if (rotationStartRef.current) {
      const stage = stageRef.current;
      if (!stage) return;
      const pointer = stage.getPointerPosition();
      if (!pointer) return;

      const centerX = position.x;
      const centerY = position.y;
      
      const currentAngle = Math.atan2(pointer.y - centerY, pointer.x - centerX) * 180 / Math.PI;
      const delta = currentAngle - rotationStartRef.current.angle;
      setRotation(rotationStartRef.current.startRotation + delta);
    }
  };

  const handleMouseUp = () => {
    rotationStartRef.current = null;
    stopMoving();
  };

  const handleDragStart = () => {
    startMoving();
  };

  const handleDragEnd = (e: any) => {
    setPosition({ x: e.target.x(), y: e.target.y() });
    stopMoving();
  };

  const sectors = [
    // Left Wing (Gate A)
    { id: 'gate_left', name: "AIRSTRIP GATE A", x: 50, y: 100, w: 320, h: 500, color: "transparent", opacity: 0 },
    { id: 'customs_left', name: "CUSTOMS INSPECTION A", x: 50, y: 620, w: 320, h: 140, color: "transparent", opacity: 0 },

    // Central Main Hall
    { id: 'lobby', name: "MAIN LOBBY & LOUNGE", x: 380, y: 100, w: 640, h: 660, color: "transparent", opacity: 0 },
    { id: 'baggage_claim', name: "BAGGAGE CLAIM", x: 390, y: 110, w: 300, h: 300, color: "transparent", opacity: 0 },
    { id: 'info_desk', name: "INFORMATION", x: 600, y: 450, w: 200, h: 100, color: "transparent", opacity: 0 },

    // Right Wing (Gate B)
    { id: 'gate_right', name: "QUARANTINE DESK B", x: 1030, y: 100, w: 350, h: 350, color: "transparent", opacity: 0 },
    { id: 'toilets', name: "1F TOILETS", x: 1030, y: 460, w: 350, h: 300, color: "transparent", opacity: 0 },
  ];

  useEffect(() => {
    const handleZoomIn = () => {
      const oldScale = scale;
      const newScale = Math.min(5, oldScale * 1.2);
      const center = { x: dimensions.width / 2, y: dimensions.height / 2 };
      const mousePointTo = { x: (center.x - position.x) / oldScale, y: (center.y - position.y) / oldScale };
      setScale(newScale);
      setPosition({ x: center.x - mousePointTo.x * newScale, y: center.y - mousePointTo.y * newScale });
    };
    const handleZoomOut = () => {
      const oldScale = scale;
      const newScale = Math.max(0.2, oldScale / 1.2);
      const center = { x: dimensions.width / 2, y: dimensions.height / 2 };
      const mousePointTo = { x: (center.x - position.x) / oldScale, y: (center.y - position.y) / oldScale };
      setScale(newScale);
      setPosition({ x: center.x - mousePointTo.x * newScale, y: center.y - mousePointTo.y * newScale });
    };
    const handleReset = () => {
      setScale(1);
      setPosition({ x: dimensions.width / 2, y: dimensions.height / 2 });
      setRotation(0);
      onDeviceSelect(null);
    };

    window.addEventListener("zoom-in-2d", handleZoomIn);
    window.addEventListener("zoom-out-2d", handleZoomOut);
    window.addEventListener("reset-2d-camera", handleReset);
    return () => {
      window.removeEventListener("zoom-in-2d", handleZoomIn);
      window.removeEventListener("zoom-out-2d", handleZoomOut);
      window.removeEventListener("reset-2d-camera", handleReset);
    };
  }, [scale, position, dimensions]);

  return (
    <div ref={containerRef} className="w-full h-full flex items-center justify-center bg-black/5 overflow-hidden relative">

      <div className="absolute top-4 right-4 z-10 flex gap-2">
        <div className="px-3 py-1 bg-black/50 backdrop-blur rounded text-[10px] text-white/50 border border-white/10 uppercase tracking-widest font-bold">
          {t("dashboard:map.rotation")} : {rotation.toFixed(0)}°
        </div>
        <div className="px-3 py-1 bg-black/50 backdrop-blur rounded text-[10px] text-white/50 border border-white/10 uppercase tracking-widest font-bold">
          {t("dashboard:map.scaling")} : {(scale * 100).toFixed(0)}%
        </div>
      </div>

      <Stage
        width={dimensions.width}
        height={dimensions.height}
        ref={stageRef}
        onWheel={handleWheel}
        scaleX={scale}
        scaleY={scale}
        rotation={rotation}
        x={position.x}
        y={position.y}
        offset={{ x: 750, y: 400 }} // 도면 중심을 기준으로 회전
        draggable
        onDragStart={handleDragStart}
        onDragEnd={handleDragEnd}
        onMouseDown={handleMouseDown}
        onMouseMove={handleMouseMove}
        onMouseUp={handleMouseUp}
        onDblClick={() => {
          // [DBL-CLICK-RESET] 화면 더블 클릭 시 초기 시점으로 완전 복구
          setScale(1);
          setPosition({ x: dimensions.width / 2, y: dimensions.height / 2 });
          setRotation(0);
          onDeviceSelect(null);
        }}
        onContextMenu={(e) => e.evt.preventDefault()} // 우클릭 메뉴 방지
      >
        <Layer
          listening={!isMoving} // [DYNAMIC-RENDER] 이동 중에는 클릭 감지 등을 중단하여 연산 절감
        >
          <MapBackground
            url={`${import.meta.env.BASE_URL}assets/platforms/quarantine/map/PUS.svg`}
            width={1500}
            height={800}
          />

          {/* [1] 가이드 그리드 복구 */}
          {Array.from({ length: 40 }).map((_, i) => (
            <React.Fragment key={i}>
              <Line points={[i * 50, 0, i * 50, 1000]} stroke={token.colorBorderSecondary} strokeWidth={0.5} opacity={0.1} />
              <Line points={[0, i * 50, 1600, i * 50]} stroke={token.colorBorderSecondary} strokeWidth={0.5} opacity={0.1} />
            </React.Fragment>
          ))}

          {/* [2] 구역 명칭 및 히트영역 복구 */}
          {sectors.map(s => (
            <React.Fragment key={s.id}>
              <Rect
                x={s.x} y={s.y} width={s.w} height={s.h}
                fill={token.colorPrimary} opacity={0.03}
                listening={false}
              />
              <Text
                x={s.x + 15} y={s.y + 15} text={s.name}
                fontSize={12} fill={token.colorTextSecondary} opacity={0.6} fontStyle="bold"
              />
            </React.Fragment>
          ))}

          {/* [3] 중앙 배경 텍스트 복구 */}
          <Text
            x={0}
            y={0}
            width={1500}
            height={800}
            text="AIRPORT"
            fontSize={120}
            fontStyle="black"
            fill={token.colorTextBase}
            opacity={0.03}
            align="center"
            verticalAlign="middle"
            listening={false}
          />

          {/* 장비 아이콘 레이어 (DB 연동) */}
          {equipmentItems.map((d) => {
            const isSelected = selectedEquipment && selectedEquipment.id === d.id;

            const handleInteract = () => {
              const stage = stageRef.current;
              if (!stage) return;

              if (isSelected) {
                // [TOGGLE-OFF] 동일 장비 재클릭 시에만 해제
                onDeviceSelect(null);
                stage.to({
                  x: dimensions.width / 2,
                  y: dimensions.height / 2,
                  scaleX: 1,
                  scaleY: 1,
                  rotation: 0,
                  duration: 0.5,
                  easing: Konva.Easings.EaseInOut,
                  onFinish: () => {
                    setPosition({ x: dimensions.width / 2, y: dimensions.height / 2 });
                    setScale(1);
                    setRotation(0);
                  }
                });
              } else {
                // [TOGGLE-ON / HANDOVER] 신규 장비 또는 교체 시 즉시 이동
                onDeviceSelect(d);
                const zoomScale = 2.0;
                const canvasWidth = stage.width();
                const canvasHeight = stage.height();

                const targetX = (canvasWidth * 0.3) - (d.x - 750) * zoomScale;
                const targetY = (canvasHeight * 0.5) - (d.y - 400) * zoomScale;

                // [SYNC-ANIMATION] React 상태와 애니메이션 동기화 강화
                // 단순히 끝난 뒤에만 바꾸는 게 아니라, 전환 중 충돌 방지를 위해 duration 최적화
                stage.to({
                  x: targetX,
                  y: targetY,
                  scaleX: zoomScale,
                  scaleY: zoomScale,
                  duration: 0.3, // 더 기민하게
                  easing: Konva.Easings.EaseOut, // EaseInOut보다 더 반응이 빠른 EaseOut
                  onFinish: () => {
                    setScale(zoomScale);
                    setPosition({ x: targetX, y: targetY });
                    onDeviceSelect(d); // 애니메이션 완료 후에 선택 정보를 띄워 버벅임 최소화
                  }
                });
              }
            };

            return (
              <Group
                key={d.id}
                x={d.x}
                y={d.y}
                rotation={-rotation} // [UPRIGHT-SYNC] 지도가 회전해도 아이콘과 텍스트는 수직 유지
                style={{ cursor: 'pointer' }}
                onClick={handleInteract}
                onTap={handleInteract}
              >
                {/* 선택 강조 효과 (강력한 아웃라인) */}
                {isSelected && (
                  <Rect
                    x={-37} y={-37} width={74} height={74}
                    stroke={token.colorPrimary}
                    strokeWidth={4} // 더 굵게
                    cornerRadius={16}
                    shadowBlur={20}
                    shadowColor={token.colorPrimary}
                    opacity={1}
                  />
                )}

                <DeviceIcon url={d.icon} x={0} y={0} size={isSelected ? 60 : 48} />
                {!isMoving && ( // [DYNAMIC-RENDER] 이동 중에는 애니메이션 요소 렌더링 중지
                  <StatusIndicator
                    x={isSelected ? 16 : 12}
                    y={isSelected ? 20 : 15}
                    status={d.status}
                    color={getStatusColor(d.status)}
                    token={token}
                  />
                )}
                <Text
                  x={-40}
                  y={isSelected ? 40 : 32}
                  width={80}
                  text={d.name}
                  fontSize={isSelected ? 12 : 10}
                  fontStyle={isSelected ? "bold" : "normal"}
                  fill={isSelected ? token.colorPrimary : token.colorTextSecondary}
                  align="center"
                />
              </Group>
            );
          })}
        </Layer>
      </Stage>
    </div>
  );
};

export default KonvaMap;
