import React from "react";
import { useTranslation } from "react-i18next";
import { Space, Typography, Button, theme } from "antd";
import { BellOutlined, CaretRightOutlined } from "@ant-design/icons";
import { QUARANTINE_DB } from "../../mocks/db";

const { Text } = Typography;

interface DashboardHeaderProps {
  isEventExpanded: boolean;
  setIsEventExpanded: (expanded: boolean) => void;
  mapMode: string;
  setMapMode: (mode: string) => void;
  setDetailEvent: (event: any) => void;
}

const DashboardHeader: React.FC<DashboardHeaderProps> = ({
  isEventExpanded,
  setIsEventExpanded,
  mapMode,
  setMapMode,
  setDetailEvent,
}) => {
  const { token } = theme.useToken();
  const { t } = useTranslation(["quarantine", "dashboard"]);

  const mockEvents = QUARANTINE_DB.recentEvents;

  return (
    <div
      className={`absolute top-0 left-0 right-0 z-50 transition-all duration-300 ease-in-out shadow-2xl overflow-hidden ${isEventExpanded ? "h-64" : "h-14"}`}
      style={{
        background: token.colorBgContainer,
        borderBottom: `1px solid ${token.colorBorderSecondary}`,
      }}
    >
      <div
        className="h-14 flex justify-between items-center px-6 cursor-pointer transition-colors absolute top-0 left-0 right-0 z-20"
        style={{ background: token.colorPrimary }}
        onClick={() => setIsEventExpanded(!isEventExpanded)}
      >
        <Space size="large">
          <BellOutlined
            className="p-2 rounded-lg"
            style={{ color: token.colorTextLightSolid, background: `${token.colorWhite}33`, fontSize: 16 }}
          />
          <Text style={{ color: token.colorTextLightSolid, fontSize: 14, fontWeight: "bold" }}>
            {t("dashboard:eventStatus")}
          </Text>
          <div className="h-4 w-[1px] mx-2" style={{ background: `${token.colorWhite}4D` }} />
          <Text style={{ color: token.colorTextLightSolid, fontSize: 14 }}>
            {t(`dashboard:${mockEvents[0].content}`)}
          </Text>
        </Space>
        <Space size="middle">
          <Text
            className="font-mono"
            style={{ color: `${token.colorTextLightSolid}E6`, fontSize: 13 }}
          >
            {mockEvents[0].time}
          </Text>
          <CaretRightOutlined
            className={`transition-transform duration-300 ${isEventExpanded ? "rotate-[-90deg]" : "rotate-90"
               }`}
            style={{ color: `${token.colorTextLightSolid}CC`, fontSize: 14 }}
          />
          <div
            className="p-1 rounded-lg flex items-center ml-4"
            style={{ background: `${token.colorWhite}1A` }}
            onClick={(e) => e.stopPropagation()}
          >
            <Button
              size="small"
              type={mapMode === "2D" ? "primary" : "text"}
              className="h-8 px-5 font-bold border-none"
              style={{ color: mapMode === "2D" ? undefined : `${token.colorTextLightSolid}80`, fontSize: 13 }}
              onClick={() => setMapMode("2D")}
            >
              {t("dashboard:mapMode.2d")}
            </Button>
            <Button
              size="small"
              type={mapMode === "3D" ? "primary" : "text"}
              className="h-8 px-5 font-bold border-none"
              style={{ color: mapMode === "3D" ? undefined : `${token.colorTextLightSolid}80`, fontSize: 13 }}
              onClick={() => setMapMode("3D")}
            >
              {t("dashboard:mapMode.3d")}
            </Button>
          </div>
        </Space>
      </div>

      <div className="pt-14 flex flex-col h-full" style={{ background: token.colorBgContainer }}>
        <div className="flex-1 overflow-y-auto px-1 py-1">
          {mockEvents.map((ev, idx) => (
            <div
              key={idx}
              className="flex justify-between items-center px-6 py-4 cursor-pointer transition-all border-b"
              style={{ borderColor: token.colorBorderSecondary }}
              onClick={() => setDetailEvent(ev)}
            >
              <Text style={{ color: token.colorTextSecondary, fontSize: 14, fontWeight: 500 }}>
                {t(`dashboard:${ev.content}`)}
              </Text>
              <Space size="large">
                <Text
                  className="font-mono"
                  style={{ color: token.colorTextQuaternary, fontSize: 13 }}
                >
                  {ev.time}
                </Text>
              </Space>
            </div>
          ))}
        </div>
        <Button
          className="w-full h-12 border-none rounded-none font-bold"
          style={{ background: token.colorPrimary, color: token.colorTextLightSolid, fontSize: 14 }}
          onClick={() => setIsEventExpanded(false)}
        >
          {t("dashboard:checkAllEvents")}
        </Button>
      </div>
    </div>
  );
};

export default DashboardHeader;
