/**
 * 무인방역 플랫폼 전용 상태 고유 색상 정의 (Legacy ICS 규격 준수)
 */
export const STATUS_COLORS = {
  ERROR: "#f7734f",     // 장애 (Red-Orange)
  WARNING: "#f2aa2d",   // 주의 (Gold)
  ONLINE: "#52c41a",    // 정상 (Green)
  OPERATION: "#53a2f2", // 운영 (Blue)
  ALARM: "#a078f7",     // 알람 (Purple)
  STANDBY: "#626b88",   // 대기 (Slate)
};

export const getStatusColor = (status: string) => {
  const s = status.toLowerCase();
  if (s === 'error' || s === 'err' || s === 'failure') return STATUS_COLORS.ERROR;
  if (s === 'warning' || s === 'warn' || s === 'cntrl') return STATUS_COLORS.WARNING;
  if (s === 'online' || s === 'success' || s === 'normal') return STATUS_COLORS.ONLINE;
  if (s === 'operation' || s === 'oprtn' || s === 'running') return STATUS_COLORS.OPERATION;
  if (s === 'alarm') return STATUS_COLORS.ALARM;
  return STATUS_COLORS.STANDBY;
};
