import React from "react";
import { useTranslation } from "react-i18next";
import {
  Typography,
  Card,
  Button,
  Space,
  Badge,
  Tag,
  Tooltip,
} from "antd";
import {
  ClockCircleOutlined,
  InfoCircleOutlined,
  ArrowRightOutlined,
  CopyOutlined,
  BarChartOutlined,
  FileTextOutlined,
  SafetyCertificateOutlined,
  PlayCircleOutlined,
  DeploymentUnitOutlined,
  CloseCircleOutlined,
  ExclamationCircleOutlined,
  SyncOutlined,
  FlagOutlined,
} from "@ant-design/icons";
import ReactECharts from "echarts-for-react";
import { QUARANTINE_DB } from "../../mocks/db";
import { getStatusColor, STATUS_COLORS } from "../../constants";

const { Text } = Typography;

interface SidebarOverlaysProps {
  token: any;
  scenario?: any;
  devices: any[];
  setEquipmentDetailGroup: (group: string | null) => void; // 상세조회 트리거
  activeLeftTab: string | null;
  setActiveLeftTab: (tab: string | null) => void;
  activeRightTab: string | null;
  setActiveRightTab: (tab: string | null) => void;
  setIsInfectionPopupOpen: (open: boolean) => void;
  setIsScenarioPopupOpen: (open: boolean) => void;
  setIsHistoryPopupOpen: (open: boolean) => void;
  getDonutOption: (label: string, current: number, total: number, color: string) => any;
}

const SidebarOverlays: React.FC<SidebarOverlaysProps> = ({
  token,
  scenario,
  devices,
  setEquipmentDetailGroup,
  activeLeftTab,
  setActiveLeftTab,
  activeRightTab,
  setActiveRightTab,
  setIsInfectionPopupOpen,
  setIsScenarioPopupOpen,
  setIsHistoryPopupOpen,
  getDonutOption,
}) => {
  const { t } = useTranslation(["quarantine", "dashboard"]);

  // 실시간 시나리오 데이터
  const currentScenario = scenario || QUARANTINE_DB.scenarios;

  // [LIVE-CALCULATION] 장비 상태 실시간 집계
  const getGroupStats = (grpCd: string) => {
    const groupDevices = devices.filter(d => d.deviceGrpCd === grpCd);
    const total = groupDevices.length;
    const errorCount = groupDevices.filter(d => d.status === 'error').length;
    const warningCount = groupDevices.filter(d => d.status === 'warning').length;
    const okCount = groupDevices.filter(d => d.status === 'online').length;
    
    return {
      total,
      cur: okCount, 
      err: errorCount,
      warning: warningCount, // [SEPARATION] 에러와 주의 분리
      ok: okCount,
      nok: errorCount + warningCount,
      unconfirm: 0
    };
  };

  const equipmentGroups = [
    { id: "baggageDisinfector", grpCd: "baggage.svg", ...getGroupStats("baggage.svg") },
    { id: "quarantineRobot", grpCd: "disinfectionRobot.svg", ...getGroupStats("disinfectionRobot.svg") },
    { id: "thermalCamera", grpCd: "feverCam.svg", ...getGroupStats("feverCam.svg") },
    { id: "serviceRobot", grpCd: "serviceRobot.svg", ...getGroupStats("serviceRobot.svg") },
  ];

  const leftTabs = [
    {
      id: "level",
      label: t("dashboard:responseLevel"),
      icon: SafetyCertificateOutlined,
      summaries: [{ label: t("dashboard:step"), val: QUARANTINE_DB.responseLevel.level, color: token.colorWarning, icon: FlagOutlined }],
    },
    {
      id: "scenario",
      label: t("dashboard:scenarioStatus"),
      icon: PlayCircleOutlined,
      summaries: [
        { label: t("dashboard:progress"), val: currentScenario.running, color: token.colorPrimary, icon: SyncOutlined },
        { label: t("dashboard:unapproved"), val: currentScenario.pending, color: token.colorWarning, icon: ClockCircleOutlined },
      ],
    },
    {
      id: "equipment",
      label: t("dashboard:equipmentStatus"),
      icon: DeploymentUnitOutlined,
      summaries: [
        { label: t("dashboard:equipment.installed"), val: QUARANTINE_DB.devices.length, color: token.colorPrimary, icon: DeploymentUnitOutlined },
        { label: t("dashboard:status.error"), val: devices.filter(d => d.status === "error").length, color: STATUS_COLORS.ERROR, icon: CloseCircleOutlined },
        { label: t("dashboard:status.warning"), val: devices.filter(d => d.status === "warning").length, color: STATUS_COLORS.WARNING, icon: ExclamationCircleOutlined },
      ],
    },
  ];

  const rightNavItems = [
    { id: "flight", icon: BarChartOutlined, label: t("dashboard:flightInfo") },
    { id: "history", icon: FileTextOutlined, label: t("dashboard:history") },
  ];

  return (
    <>
      {/* Left Sidebar */}
      <div className="absolute left-0 top-0 bottom-0 z-[60] flex pointer-events-none p-4 pt-20">
        <div className="w-16 h-full flex flex-col gap-3 pointer-events-auto">
          {leftTabs.map((v) => (
            <div key={v.id} className="flex items-center gap-3 group/tab pointer-events-auto">
              <div
                onClick={() => setActiveLeftTab(activeLeftTab === v.id ? null : v.id)}
                className={`w-14 min-h-[140px] backdrop-blur-lg rounded-r-2xl flex flex-col items-center justify-between py-6 border-y border-r cursor-pointer transition-all ${
                  activeLeftTab === v.id ? "z-30 w-16" : "z-10"
                }`}
                style={{
                  background:
                    activeLeftTab === v.id ? token.colorFillSecondary : token.colorBgElevated + "99",
                  borderColor: token.colorBorderSecondary,
                }}
              >
                <div className="flex flex-col items-center gap-4">
                  <v.icon style={{ fontSize: 18, color: activeLeftTab === v.id ? token.colorText : `${token.colorTextLightSolid}80` }} />
                  <div
                    className="[writing-mode:vertical-lr] text-[13px] font-bold tracking-[0.2em] uppercase"
                    style={{ color: activeLeftTab === v.id ? token.colorText : `${token.colorTextLightSolid}B3` }}
                  >
                    {v.label}
                  </div>
                </div>
              </div>

              {/* Notification summaries sitting on the right side */}
              <div className="flex flex-col gap-2">
                {v.summaries.map((s, si) => (
                  <Tooltip key={si} title={s.label} placement="right">
                    <div
                      className="w-11 h-11 rounded-full flex flex-col items-center justify-center shadow-lg relative border transition-all hover:scale-110 active:scale-95 cursor-help"
                      style={{ background: token.colorBgContainer, borderColor: `${token.colorWhite}1A` }}
                    >
                      <div
                        className="absolute -top-1 -right-1 w-5 h-5 rounded-full flex items-center justify-center text-[10px] font-bold shadow-md"
                        style={{ 
                          background: s.color, 
                          color: "#fff",
                          boxShadow: s.color === token.colorError || s.color === token.colorWarning 
                            ? `0 0 10px ${s.color}` 
                            : "none" 
                        }}
                      >
                        {s.val}
                      </div>
                      {s.icon && <s.icon style={{ fontSize: 16, color: "rgba(255,255,255,0.4)" }} />}
                    </div>
                  </Tooltip>
                ))}
              </div>
            </div>
          ))}
        </div>

        <div className="flex flex-col gap-4 p-4 pointer-events-auto overflow-hidden">
          {activeLeftTab === "level" && (
            <div className="animate-in slide-in-from-left duration-300 ease-out fill-mode-forwards">
              <Card
                size="small"
                className="w-[620px] backdrop-blur-3xl border shadow-[0_25px_60px_rgba(0,0,0,0.8)]"
                style={{
                  background: `${token.colorBgContainer}f2`,
                  borderColor: token.colorBorderSecondary,
                  borderRadius: "16px",
                }}
                styles={{ body: { padding: "16px 20px" } }}
              >
                <div className="flex gap-6">
                  <div className="w-[260px]">
                    <div className="flex justify-between items-center mb-4 px-1">
                      <Text
                        style={{ color: token.colorTextDescription, fontSize: 14, fontWeight: "bold" }}
                      >
                        {t("dashboard:responseLevel")}{" "}
                        <span style={{ color: token.colorWarning }}>{t("dashboard:levelFormat", { val: QUARANTINE_DB.responseLevel.level })}</span>
                      </Text>
                    </div>
                    <div className="grid grid-cols-5 gap-2">
                      {[1, 2, 3, 4, 5].map((lv) => (
                        <div
                          key={lv}
                          className={`h-10 rounded-lg flex items-center justify-center text-sm font-bold transition-all ${
                            lv === QUARANTINE_DB.responseLevel.level
                              ? "opacity-100 shadow-[0_0_0_2px_rgba(250,140,22,0.4)]"
                              : "opacity-40 hover:opacity-60"
                          }`}
                          style={{
                            background: lv === QUARANTINE_DB.responseLevel.level ? token.colorWarning : token.colorFillAlter,
                            color: lv === QUARANTINE_DB.responseLevel.level ? token.colorBgBase : token.colorTextDescription,
                          }}
                        >
                          {lv}
                        </div>
                      ))}
                    </div>
                  </div>
                  <div
                    className="w-[1px] self-stretch my-2"
                    style={{ background: token.colorBorderSecondary }}
                  />
                  <div className="flex-1">
                    <div className="flex justify-between items-center mb-4 px-1">
                      <Text
                        style={{ color: token.colorTextDescription, fontSize: 14, fontWeight: "bold" }}
                      >
                        {t("dashboard:flight.arrival")}{" "}
                        <span style={{ color: token.colorPrimary }}>{t("dashboard:levelFormat", { val: 3 })}</span>
                      </Text>
                      <div className="flex items-center gap-2">
                        <Button
                          type="text"
                          size="small"
                          icon={<InfoCircleOutlined style={{ color: token.colorTextQuaternary, fontSize: 16 }} />}
                          className="p-1 h-auto flex items-center"
                          onClick={() => setIsInfectionPopupOpen(true)}
                        />
                      </div>
                    </div>
                    <div
                      className="p-3 rounded-xl border flex justify-between items-center"
                      style={{ background: token.colorBgLayout, borderColor: token.colorBorderSecondary }}
                    >
                      <Text
                        style={{ color: token.colorTextQuaternary, fontSize: 13, fontWeight: "bold" }}
                      >
                        {t("dashboard:confirmedCase")}
                      </Text>
                      <Text
                        className="font-mono font-bold"
                        style={{ color: token.colorText, fontSize: 16 }}
                      >
                        44,553,042{" "}
                        <span
                          style={{ color: token.colorTextQuaternary, fontSize: 12, fontWeight: "normal" }}
                        >
                          {t("dashboard:unit.person")}
                        </span>
                      </Text>
                    </div>
                  </div>
                </div>
              </Card>
            </div>
          )}

          {activeLeftTab === "scenario" && (
            <div className="animate-in slide-in-from-left duration-500 ease-out">
              <Card
                size="small"
                title={
                  <div className="flex justify-between items-center w-full px-1">
                    <Text
                      style={{ color: token.colorTextSecondary, fontSize: 13, fontWeight: "bold" }}
                    >
                      {t("dashboard:scenario.dailyStatus")}
                    </Text>
                    <Button
                      type="text"
                      size="small"
                      icon={
                        <ArrowRightOutlined
                          style={{ color: token.colorTextQuaternary, fontSize: 14 }}
                        />
                      }
                      className="p-1 h-auto flex items-center"
                      onClick={() => setIsScenarioPopupOpen(true)}
                    />
                  </div>
                }
                className="w-[520px] backdrop-blur-xl border shadow-2xl"
                style={{
                  background: `${token.colorBgContainer}f2`,
                  borderColor: token.colorBorderSecondary,
                  borderRadius: "16px",
                }}
                styles={{ body: { padding: "20px" } }}
              >
                <div className="grid grid-cols-3 gap-4 mb-5">
                  {[
                    { label: t("dashboard:progress"), val: currentScenario.running, color: token.colorInfo },
                    { label: t("dashboard:complete"), val: currentScenario.completed, color: token.colorSuccess },
                    { label: t("dashboard:unapproved"), val: currentScenario.pending, color: token.colorWarning },
                  ].map((s, i) => (
                    <div
                      key={i}
                      className="flex flex-col p-4 rounded-xl border-l-4 shadow-sm"
                      style={{ background: token.colorBgLayout, borderColor: s.color }}
                    >
                      <Text
                        style={{ color: token.colorTextQuaternary, fontSize: 13, fontWeight: "bold", marginBottom: 8 }}
                      >
                        {s.label}
                      </Text>
                      <div className="flex justify-end">
                        <Text
                          className="font-mono font-bold"
                          style={{ color: token.colorText, fontSize: 16 }}
                        >
                          {s.val}
                        </Text>
                      </div>
                    </div>
                  ))}
                </div>
                <div className="p-5 rounded-xl border flex items-center gap-6" style={{ background: token.colorBgLayout, borderColor: token.colorBorderSecondary }}>
                  <div className="flex-1">
                    <Text
                      className="block mb-2"
                      style={{ color: token.colorTextDescription, fontSize: 13, fontWeight: "bold" }}
                    >
                      {t(`dashboard:${currentScenario.activeTitle}`)}
                    </Text>
                    {/* [LIVE-STATUS-MESSAGE] 실시간 단계 메시지 표시 */}
                    <Text
                      className="block mb-4 italic"
                      style={{ color: token.colorPrimary, fontSize: 11 }}
                    >
                      {currentScenario.activeStatusMsg || t("dashboard:monitoring")}
                    </Text>
                    <div
                      className="relative h-4 rounded-full overflow-hidden"
                      style={{ background: token.colorFillAlter }}
                    >
                      <div
                        className="absolute inset-0 transition-all duration-300"
                        style={{
                          width: `${currentScenario.progress}%`,
                          background: `linear-gradient(90deg, ${token.colorPrimary}88, ${token.colorPrimary})`,
                        }}
                      />
                    </div>
                  </div>
                  <div>
                    <Text className="font-mono font-bold" style={{ color: token.colorText, fontSize: 14 }}>
                      {currentScenario.progress} %
                    </Text>
                  </div>
                </div>
              </Card>
            </div>
          )}

          {activeLeftTab === "equipment" && (
            <div className="animate-in slide-in-from-left duration-500 ease-out">
              <Card
                size="small"
                title={
                  <div className="flex justify-between items-center w-full px-1">
                    <Text
                      style={{ color: token.colorTextSecondary, fontSize: 13, fontWeight: "bold" }}
                    >
                      {t("dashboard:equipmentStatus")}
                    </Text>
                    <Button
                      type="text"
                      size="small"
                      icon={
                        <ArrowRightOutlined
                          style={{ color: token.colorPrimary, fontSize: 14 }}
                        />
                      }
                      className="p-1 h-auto flex items-center"
                      onClick={() => setEquipmentDetailGroup("all")} // [ALL-VIEW] 전체 보기 트리거
                    />
                  </div>
                }
                className="w-[820px] backdrop-blur-xl border shadow-2xl"
                style={{
                  background: `${token.colorBgContainer}f2`,
                  borderColor: token.colorBorderSecondary,
                  borderRadius: "16px",
                }}
                styles={{ body: { padding: "20px" } }}
              >
                <div className="grid grid-cols-2 gap-5">
                  {/* [DYNAMIC-EQUIPMENT-CARDS] 실시간 집계된 장비 그룹 렌더링 */}
                  {equipmentGroups.map((item, idx) => (
                    <div
                      key={idx}
                      className="p-4 rounded-xl flex gap-5 items-center shadow-sm relative group cursor-default"
                      style={{ background: token.colorBgLayout, border: `1px solid ${token.colorBorderSecondary}` }}
                    >
                      {/* [DETAIL-TRIGGER] 상세 조회 화살표 버튼 */}
                      <div 
                        className="absolute top-3 right-3 opacity-40 group-hover:opacity-100 transition-opacity cursor-pointer p-1 rounded-md hover:bg-white/10"
                        onClick={() => setEquipmentDetailGroup(item.id)}
                      >
                        <ArrowRightOutlined style={{ color: token.colorPrimary, fontSize: 16 }} />
                      </div>
                      <div className="w-24 h-24 shrink-0 relative">
                        <ReactECharts
                          option={getDonutOption(
                            "", 
                            item.cur, 
                            item.total, 
                            item.err > 0 ? STATUS_COLORS.ERROR : (item.warning > 0 ? STATUS_COLORS.WARNING : STATUS_COLORS.ONLINE)
                          )}
                          style={{ height: "100%", width: "100%" }}
                        />
                        <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
                          <Text
                            className="font-bold leading-none"
                            style={{ color: token.colorText, fontSize: 13 }}
                          >
                            {item.cur}
                            <span style={{ color: token.colorTextQuaternary }}>/{item.total}</span>
                          </Text>
                        </div>
                      </div>
                      <div className="flex-1 space-y-2">
                        <Text
                          className="block truncate font-bold"
                          style={{ color: token.colorText, fontSize: 14 }}
                        >
                          {t(`dashboard:equipments.${item.id}`)}
                        </Text>
                        <div
                          className="flex justify-between items-center px-3 py-1 rounded-lg"
                          style={{ background: token.colorFillAlter }}
                        >
                          <Text style={{ color: token.colorTextQuaternary, fontSize: 13, fontWeight: "bold" }}>
                            {t("dashboard:error")}
                          </Text>
                          <Badge
                            count={item.err}
                            size="small"
                            style={{
                              backgroundColor:
                                item.err > 0 ? token.colorError : token.colorFillSecondary,
                              fontSize: "13px",
                              minWidth: "22px",
                              height: "22px",
                              lineHeight: "22px",
                            }}
                          />
                        </div>
                        <div
                          className="flex justify-between items-center px-3 py-1 rounded-lg"
                          style={{ background: token.colorFillAlter }}
                        >
                          <Text style={{ color: token.colorTextSecondary, fontSize: 13, fontWeight: "bold" }}>
                            {t("dashboard:equipment.unconfirmedEvent")}
                          </Text>
                          <Badge
                            count={item.unconfirm}
                            size="small"
                            style={{
                              backgroundColor: item.unconfirm > 0 ? token.colorInfo : token.colorFillSecondary,
                              color: item.unconfirm > 0 ? "#fff" : token.colorTextSecondary,
                              fontSize: "13px",
                              minWidth: "22px",
                              height: "22px",
                              lineHeight: "22px",
                            }}
                          />
                        </div>
                        <div className="flex gap-2">
                          <div
                            className="flex-1 flex justify-between items-center px-2 py-1 rounded-lg"
                            style={{ 
                              background: item.err > 0 ? `${STATUS_COLORS.ERROR}26` : token.colorFillAlter,
                              border: item.err > 0 ? `1px solid ${STATUS_COLORS.ERROR}40` : "none" 
                            }}
                          >
                            <CloseCircleOutlined style={{ color: item.err > 0 ? STATUS_COLORS.ERROR : token.colorTextQuaternary, fontSize: 15 }} />
                            <Text
                              style={{ 
                                color: item.err > 0 ? STATUS_COLORS.ERROR : token.colorTextSecondary, 
                                fontSize: 14, 
                                fontWeight: "black",
                                marginLeft: 4
                              }}
                            >
                              {item.err}
                            </Text>
                          </div>
                          <div
                            className="flex-1 flex justify-between items-center px-2 py-1 rounded-lg"
                            style={{ 
                              background: item.warning > 0 ? `${STATUS_COLORS.WARNING}26` : token.colorFillAlter,
                              border: item.warning > 0 ? `1px solid ${STATUS_COLORS.WARNING}40` : "none"
                            }}
                          >
                            <ExclamationCircleOutlined style={{ color: item.warning > 0 ? STATUS_COLORS.WARNING : token.colorTextQuaternary, fontSize: 15 }} />
                            <Text
                              style={{
                                color: item.warning > 0 ? STATUS_COLORS.WARNING : token.colorTextSecondary,
                                fontSize: 14,
                                fontWeight: "black",
                                marginLeft: 4
                              }}
                            >
                              {item.warning}
                            </Text>
                          </div>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              </Card>
            </div>
          )}
        </div>
      </div>

      {/* Right Sidebar */}
      <div className="absolute right-0 top-0 bottom-0 z-[60] flex flex-row-reverse pointer-events-none p-4 pt-20">
        <div className="w-16 h-full flex flex-col gap-2 pointer-events-auto">
          {rightNavItems.map((v) => (
            <div
              key={v.id}
              onClick={() => setActiveRightTab(activeRightTab === v.id ? null : v.id)}
              className={`w-14 min-h-[160px] backdrop-blur-lg rounded-l-2xl flex flex-col items-center justify-center p-2 border-y border-l cursor-pointer transition-all ${
                activeRightTab === v.id ? "z-30 w-16" : "z-10"
              }`}
              style={{
                background:
                  activeRightTab === v.id ? token.colorFillSecondary : token.colorBgElevated + "99",
                borderColor: token.colorBorderSecondary,
              }}
            >
              <div className="mb-4 scale-150" style={{ color: activeRightTab === v.id ? token.colorText : token.colorTextQuaternary }}>
                <v.icon />
              </div>
              <div
                className={`[writing-mode:vertical-lr] text-[13px] font-bold tracking-[0.2em] uppercase`}
                style={{ color: activeRightTab === v.id ? token.colorText : `${token.colorTextLightSolid}B3` }}
              >
                {v.label}
              </div>
            </div>
          ))}
        </div>

        <div className="flex flex-col gap-4 p-4 pointer-events-auto overflow-hidden">
          {activeRightTab === "flight" && (
            <div className="animate-in slide-in-from-right duration-500 ease-out">
              <Card
                size="small"
                title={
                  <div className="px-1 py-1">
                    <Text style={{ color: token.colorTextSecondary, fontSize: 13, fontWeight: "bold" }}>
                      {t("dashboard:flightInfo")}
                    </Text>
                  </div>
                }
                className="w-[380px] backdrop-blur-xl border shadow-2xl"
                style={{
                  background: `${token.colorBgContainer}f2`,
                  borderColor: token.colorBorderSecondary,
                  borderRadius: "16px",
                }}
                styles={{ body: { padding: "16px", maxHeight: "600px", overflowY: "auto" } }}
              >
                <div className="space-y-4">
                  {QUARANTINE_DB.flights.map((f, i) => (
                    <div
                      key={i}
                      className="p-5 rounded-xl border flex flex-col gap-2 transition-all shadow-sm"
                      style={{ background: token.colorBgLayout, borderColor: token.colorBorderSecondary }}
                    >
                      <div className="flex items-center gap-3 mb-1">
                        <Tag
                          style={{ 
                            background: f.type === "departure" ? token.colorPrimary : token.colorWarning, 
                            color: token.colorTextLightSolid, 
                            border: "none", 
                            borderRadius: 100, 
                            padding: "0 12px", 
                            fontSize: 13, 
                            fontWeight: "bold" 
                          }}
                        >
                          {f.type === "departure" ? t("dashboard:flight.departure") : t("dashboard:flight.arrival")}
                        </Tag>
                        <Text
                          style={{ color: token.colorTextSecondary, fontSize: 14, fontWeight: "bold" }}
                        >
                          {f.id}
                        </Text>
                      </div>
                      <Text
                        style={{ color: token.colorTextDescription, fontSize: 13, fontWeight: "bold" }}
                      >
                        {f.airline} ( {f.from} → {f.to} )
                      </Text>
                      <div className="mt-2 space-y-1">
                        <Text className="block" style={{ color: token.colorTextQuaternary, fontSize: 13 }}>
                          {t("dashboard:flight.changed")} : <span style={{ color: token.colorTextDescription }}>{f.changed}</span>
                        </Text>
                        <Text className="block" style={{ color: token.colorTextQuaternary, fontSize: 13 }}>
                          {t("dashboard:flight.scheduled")} : <span style={{ color: token.colorTextDescription }}>{f.scheduled}</span>
                        </Text>
                        <Text className="block" style={{ color: token.colorTextQuaternary, fontSize: 13 }}>
                          {t("dashboard:flight.gate")} : <span style={{ color: token.colorPrimary, fontWeight: "bold" }}>{f.gate}</span>
                        </Text>
                      </div>
                    </div>
                  ))}
                </div>
              </Card>
            </div>
          )}

          {activeRightTab === "history" && (
            <div className="animate-in slide-in-from-right duration-500 ease-out">
              <Card
                size="small"
                title={
                  <div className="flex justify-between items-center w-full px-1 py-1">
                    <Text
                      style={{ color: token.colorTextSecondary, fontSize: 13, fontWeight: "bold" }}
                    >
                      {t("dashboard:history")}
                    </Text>
                    <Button
                      type="text"
                      size="small"
                      icon={
                        <ArrowRightOutlined
                          style={{ color: token.colorTextQuaternary, fontSize: 14 }}
                        />
                      }
                      className="p-1 h-auto flex items-center"
                      onClick={() => setIsHistoryPopupOpen(true)}
                    />
                  </div>
                }
                className="w-[680px] backdrop-blur-xl border shadow-2xl"
                style={{
                  background: `${token.colorBgContainer}f2`,
                  borderColor: token.colorBorderSecondary,
                  borderRadius: "16px",
                }}
                styles={{ body: { padding: "16px", maxHeight: "650px", overflowY: "auto" } }}
              >
                <div className="space-y-3">
                  {QUARANTINE_DB.history.map((item, idx) => (
                    <div
                      key={idx}
                      className={`p-5 rounded-xl border flex gap-6 items-center transition-all shadow-sm`}
                      style={{
                        background: token.colorBgLayout,
                        borderColor: idx === 0 ? token.colorPrimary : token.colorBorderSecondary,
                      }}
                    >
                      <div className="w-36 shrink-0 flex items-center gap-3">
                        <div
                          className={`w-7 h-7 rounded-full flex items-center justify-center shadow-sm`}
                          style={{
                            background:
                              item.status === "success"
                                ? `${token.colorSuccess}26`
                                : `${token.colorWarning}26`,
                            color: item.status === "success" ? token.colorSuccess : token.colorWarning,
                          }}
                        >
                          {item.status === "success" ? (
                            <ClockCircleOutlined style={{ fontSize: 13 }} />
                          ) : (
                            <InfoCircleOutlined style={{ fontSize: 13 }} />
                          )}
                        </div>
                        <Text
                          style={{ color: item.status === "success" ? token.colorSuccess : token.colorWarning, fontSize: 13, fontWeight: "bold" }}
                        >
                          {t(`dashboard:${item.action}`)}
                        </Text>
                      </div>
                      <div className="w-[1px] h-12" style={{ background: token.colorBorderSecondary }} />
                      <div className="flex-1">
                        <div className="flex justify-between items-start mb-2">
                          <Space size={6}>
                            <BarChartOutlined
                              style={{ color: token.colorTextQuaternary, fontSize: 14 }}
                            />
                            <Text
                              style={{ color: token.colorTextSecondary, fontSize: 14, fontWeight: "bold" }}
                            >
                              {item.target}
                            </Text>
                          </Space>
                          <Text
                            className="font-mono"
                            style={{ color: token.colorTextQuaternary, fontSize: 12 }}
                          >
                            {item.time}
                          </Text>
                        </div>
                        <div className="flex justify-between items-center">
                          <Space size={6}>
                            <FileTextOutlined
                              style={{ color: token.colorTextQuaternary, fontSize: 14 }}
                            />
                            <Text style={{ color: token.colorTextQuaternary, fontSize: 13 }}>
                              {item.detail}
                            </Text>
                          </Space>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              </Card>
            </div>
          )}
        </div>
      </div>
    </>
  );
};

export default SidebarOverlays;
